function getMarketScopeLabel(_scopeId: MarketScopeId): string {
  return "Global Trading Post";
}

async function loadCachedMarketCatalog(
  scopeId: MarketScopeId,
): Promise<{ items: MarketItem[]; updatedAt: number } | null> {
  if (!window.gw2Desktop?.loadMarketCatalog) {
    return null;
  }

  const candidateScopeIds = [
    scopeId,
    "region:europe",
    "region:north-america",
  ].filter((candidate, index, candidates) => candidates.indexOf(candidate) === index);

  for (const candidateScopeId of candidateScopeIds) {
    try {
      const cached = await window.gw2Desktop.loadMarketCatalog(candidateScopeId);
      if (!cached) {
        continue;
      }

      const items = cached.items.filter(isCachedMarketItem).map(normalizeMarketItemPricing);
      if (items.length === 0) {
        continue;
      }

      hydrateTradingPostCatalogCache(items);
      const updatedAt = new Date(cached.updatedAt).getTime();
      return {
        items,
        updatedAt: Number.isFinite(updatedAt) ? updatedAt : Date.now(),
      };
    } catch {
      // Try the next legacy scope if a previous build saved market data there.
    }
  }

  return null;
}

async function saveCachedMarketCatalog(scopeId: MarketScopeId, items: MarketItem[]) {
  if (!window.gw2Desktop?.saveMarketCatalog || items.length === 0) {
    return;
  }

  try {
    await window.gw2Desktop.saveMarketCatalog(scopeId, items);
  } catch {
    // A failed cache write should not make live market loading feel broken.
  }
}

function mergeMarketItemMetadata(next: MarketItem, previous?: MarketItem): MarketItem {
  const normalizedNext = normalizeMarketItemPricing(next);

  if (!previous) {
    return normalizedNext;
  }

  return {
    ...previous,
    ...normalizedNext,
    icon: normalizedNext.icon || previous.icon,
    description: normalizedNext.description ?? previous.description,
    chat_link: normalizedNext.chat_link ?? previous.chat_link,
    details: normalizedNext.details ?? previous.details,
    default_skin: normalizedNext.default_skin ?? previous.default_skin,
    flags: normalizedNext.flags ?? previous.flags,
    game_types: normalizedNext.game_types ?? previous.game_types,
    restrictions: normalizedNext.restrictions ?? previous.restrictions,
    price: normalizedNext.price,
    netSellPrice: normalizedNext.netSellPrice,
    spread: normalizedNext.spread,
    spreadPercent: normalizedNext.spreadPercent,
  };
}

function normalizeMarketItemPricing(item: MarketItem): MarketItem {
  const netSellPrice = getTradingPostNetValue(item.price.sells.unit_price);
  const spread = getMarketNetSpread(item);

  return {
    ...item,
    netSellPrice,
    spread,
    spreadPercent: item.price.buys.unit_price > 0 ? (spread / item.price.buys.unit_price) * 100 : 0,
  };
}

function isCachedMarketItem(value: unknown): value is MarketItem {
  if (!value || typeof value !== "object") {
    return false;
  }

  const item = value as Partial<MarketItem>;
  const price = (item as {
    price?: {
      id?: unknown;
      buys?: { quantity?: unknown; unit_price?: unknown };
      sells?: { quantity?: unknown; unit_price?: unknown };
    };
  }).price;

  return (
    typeof item.id === "number" &&
    typeof item.name === "string" &&
    typeof item.type === "string" &&
    typeof item.rarity === "string" &&
    typeof item.level === "number" &&
    typeof item.vendor_value === "number" &&
    typeof item.netSellPrice === "number" &&
    typeof item.spread === "number" &&
    typeof item.spreadPercent === "number" &&
    typeof price?.id === "number" &&
    typeof price.buys?.quantity === "number" &&
    typeof price.buys?.unit_price === "number" &&
    typeof price.sells?.quantity === "number" &&
    typeof price.sells?.unit_price === "number"
  );
}

function ApiStatusPanel({
  apiStatusState,
  apiStatuses,
  onRefreshApiStatuses,
}: {
  apiStatusState: LoadState;
  apiStatuses: ApiStatusResult[];
  onRefreshApiStatuses: () => void;
}) {
  const issueStatuses = apiStatuses.filter((status) => status.state !== "not_configured" && !status.ok);
  const missingUserApi = apiStatuses.some((status) => status.group === "User GW2 API" && status.state === "not_configured");
  const allOk = apiStatuses.length > 0 && issueStatuses.length === 0;
  const warningSummary = getApiStatusWarningSummary(issueStatuses);
  const grouped = apiStatuses.reduce<Record<string, ApiStatusResult[]>>((groups, status) => {
    groups[status.group] = groups[status.group] ?? [];
    groups[status.group].push(status);
    return groups;
  }, {});

  return (
    <section className="api-status-panel">
      <div className="api-status-head">
        <div>
          <span className="eyebrow">API Status</span>
          <h3>{allOk ? (missingUserApi ? "Public systems operational" : "All systems operational") : "Service check"}</h3>
        </div>
        {apiStatusState === "loading" ? (
          <Loader2 className="spin" />
        ) : allOk ? (
          <CheckCircle2 className="ok" />
        ) : (
          <ApiWarningIcon message={warningSummary} placement="head" />
        )}
      </div>

      <button className="refresh-status" onClick={onRefreshApiStatuses} disabled={apiStatusState === "loading"}>
        <RefreshCcw className={apiStatusState === "loading" ? "spin" : undefined} />
        Check again
      </button>

      {apiStatusState === "loading" && apiStatuses.length === 0 ? <SkeletonRows /> : null}
      {Object.entries(grouped).map(([group, statuses]) => (
        <section key={group} className="status-group">
          <h3>{group}</h3>
          {statuses.map((status) => (
            <div
              key={`${status.group}-${status.label}`}
              className={`status-row ${getApiStatusClass(status)}`}
            >
              {getApiStatusIcon(status)}
              <span>{status.label} </span>
              <strong>{getApiStatusText(status)}</strong>
            </div>
          ))}
        </section>
      ))}
    </section>
  );
}

function ApiWarningIcon({ message, placement = "row" }: { message: string; placement?: "head" | "row" }) {
  return (
    <span className={`api-warning-icon ${placement}`} tabIndex={0} aria-label={message}>
      <AlertCircle className="warn" />
      <span className="api-warning-tooltip" role="tooltip">
        {message}
      </span>
    </span>
  );
}

function getApiStatusClass(status: ApiStatusResult): string {
  if (status.state === "not_configured") {
    return "missing";
  }

  return status.ok ? "online" : "issue";
}

function getApiStatusIcon(status: ApiStatusResult): ReactNode {
  if (status.state === "not_configured") {
    return <X className="bad" />;
  }

  return status.ok ? <CheckCircle2 className="ok" /> : <ApiWarningIcon message={getApiStatusIssueMessage(status)} />;
}

function getApiStatusText(status: ApiStatusResult): string {
  if (status.state === "not_configured") {
    return "Not provided";
  }

  const label = status.ok ? "Operational" : status.status === 401 ? "Invalid key" : "Issue";
  return status.latencyMs ? `${label} ${status.latencyMs}ms` : label;
}

function getApiStatusWarningSummary(statuses: ApiStatusResult[]): string {
  if (statuses.length === 0) {
    return "No endpoint issues detected.";
  }

  return statuses.map((status) => `${status.label}: ${getApiStatusIssueMessage(status)}`).join("\n");
}

function getApiStatusIssueMessage(status: ApiStatusResult): string {
  if (status.error) {
    return `Request failed: ${status.error}`;
  }

  if (status.status === 401) {
    return "The request was rejected as unauthorized. Check that the saved GW2 API key is valid and has the needed permissions.";
  }

  if (status.status === 403) {
    return "The GW2 API refused this request. The endpoint may require different permissions or the request may be blocked.";
  }

  if (status.status === 404) {
    return "The endpoint or sample item used for this check was not found.";
  }

  if (status.status === 429) {
    return "The GW2 API rate limit was reached. Wait a little before checking or scanning again.";
  }

  if (typeof status.status === "number" && status.status >= 500) {
    return `The GW2 API returned HTTP ${status.status}, which usually means the service is having trouble.`;
  }

  if (typeof status.status === "number") {
    return `The endpoint returned HTTP ${status.status} instead of a successful response.`;
  }

  return "The endpoint did not return a successful response.";
}

function AccountDashboard({
  accountSnapshot,
  accountItems,
  analysis,
  analysisState,
  apiKey,
  apiKeyRemembered,
  apiStatuses,
  apiStatusState,
  catalog,
  dataImports,
  marketLoadState,
  startupSettings,
  startupSettingsState,
  onAnalyze,
  onApiKeyChange,
  onForgetApiKey,
  onOpenActivity,
  onOpenItemSearch,
  onLoadMarket,
  onRefreshApiStatuses,
  onSaveApiKey,
  onStartupOpenAtLoginChange,
}: {
  accountSnapshot: AccountSnapshot | null;
  accountItems: Map<number, Gw2Item>;
  analysis: AccountAnalysis | null;
  analysisState: LoadState;
  apiKey: string;
  apiKeyRemembered: boolean;
  apiStatuses: ApiStatusResult[];
  apiStatusState: LoadState;
  catalog: MarketItem[];
  dataImports: DataImportRow[];
  marketLoadState: LoadState;
  startupSettings: StartupSettings | null;
  startupSettingsState: LoadState;
  onAnalyze: () => void;
  onApiKeyChange: (value: string) => void;
  onForgetApiKey: () => void;
  onOpenActivity: (suggestion: GoldSuggestion) => void;
  onOpenItemSearch: (itemName: string) => void;
  onLoadMarket: () => void;
  onRefreshApiStatuses: () => void;
  onSaveApiKey: () => void;
  onStartupOpenAtLoginChange: (openAtLogin: boolean) => void;
}) {
  const holdingRows = useMemo(() => {
    if (!accountSnapshot) {
      return [];
    }

    return Array.from(accountSnapshot.holdings.entries())
      .map(([id, count]) => {
        const item = accountItems.get(id) ?? getStoredItem(id);
        const price = getStoredPrice(id);
        const value = (price?.buys.unit_price ?? 0) * count;

        return {
          id,
          count,
          item,
          value,
        };
      })
      .sort((left, right) => right.value - left.value || right.count - left.count)
      .slice(0, 12);
  }, [accountItems, accountSnapshot]);

  const totalItemValue = holdingRows.reduce((sum, row) => sum + row.value, 0);
  const totalStacks = accountSnapshot
    ? Array.from(accountSnapshot.holdings.values()).reduce((sum, count) => sum + count, 0)
    : 0;
  const suggestions = buildGoldSuggestions(analysis);

  return (
    <div className="account-page">
      <section className="page-header">
        <div>
          <span className="eyebrow">First page</span>
          <h2>Your GW2 Account</h2>
          <p>
            {accountSnapshot
              ? `${accountSnapshot.tokenInfo.name} is loaded locally.`
              : "Generalized market and farming view until a GW2 API key is saved."}
          </p>
        </div>
        <div className="account-header-side">
          <ApiStatusPanel
            apiStatusState={apiStatusState}
            apiStatuses={apiStatuses}
            onRefreshApiStatuses={onRefreshApiStatuses}
          />
          <div className="page-actions">
            <button className="icon-button" onClick={onLoadMarket} disabled={marketLoadState === "loading"}>
              {marketLoadState === "loading" ? <Loader2 className="spin" /> : <RefreshCcw />}
              <span>{marketLoadState === "loading" ? "Loading Market" : catalog.length ? "Refresh Market" : "Load Market"}</span>
            </button>
            <button className="icon-button primary" onClick={onAnalyze}>
              {analysisState === "loading" ? <Loader2 className="spin" /> : <ShieldCheck />}
              <span>{accountSnapshot ? "Refresh Account" : "Analyze API"}</span>
            </button>
          </div>
        </div>
      </section>

      <section className="account-metrics">
        <Metric
          icon={<Coins />}
          label="Wallet"
          value={accountSnapshot ? <Money value={accountSnapshot.coins} /> : "General"}
        />
        <Metric
          icon={<Boxes />}
          label="Tracked Items"
          value={accountSnapshot ? totalStacks.toLocaleString() : `${catalog.length.toLocaleString()} market`}
        />
        <Metric
          icon={<TrendingUp />}
          label="Known Item Value"
          value={accountSnapshot ? <Money value={totalItemValue} /> : "Load account"}
        />
        <Metric
          icon={<Hammer />}
          label="Craft Routes"
          value={analysis ? analysis.opportunities.length.toLocaleString() : "General"}
          tone={analysis ? "positive" : "muted"}
        />
      </section>

      <AccountSettingsPanel
        apiKey={apiKey}
        apiKeyRemembered={apiKeyRemembered}
        analysisState={analysisState}
        startupSettings={startupSettings}
        startupSettingsState={startupSettingsState}
        onAnalyze={onAnalyze}
        onApiKeyChange={onApiKeyChange}
        onForgetApiKey={onForgetApiKey}
        onSaveApiKey={onSaveApiKey}
        onStartupOpenAtLoginChange={onStartupOpenAtLoginChange}
      />

      <DataImportsPanel imports={dataImports} />

      <section className="dashboard-grid">
        <div className="surface suggestions-panel">
          <div className="section-title">
            <TrendingUp />
            <h3>Gold Options</h3>
          </div>
          {analysisState === "loading" ? (
            <SkeletonRows />
          ) : (
            <div className="earning-list">
              {suggestions.slice(0, 20).map((suggestion, index) => (
                <button
                  key={`${suggestion.title}-${index}`}
                  className="earning-row"
                  onClick={() => onOpenActivity(suggestion)}
                >
                  <span className={`speed-badge speed-${suggestion.speed.toLowerCase()}`}>
                    {suggestion.speed}
                  </span>
                  <div>
                    <strong>{suggestion.title}</strong>
                    <span>{suggestion.detail}</span>
                  </div>
                  <strong>
                    {suggestion.valueCoin !== undefined ? (
                      <>
                        <Money value={suggestion.valueCoin} /> profit
                      </>
                    ) : (
                      suggestion.value
                    )}
                  </strong>
                </button>
              ))}
            </div>
          )}
        </div>

        <div className="surface holdings-panel">
          <div className="section-title">
            <Boxes />
            <h3>Items</h3>
          </div>
          {accountSnapshot ? (
            <div className="holding-list">
              {holdingRows.map((row) => (
                <button
                  key={row.id}
                  className="holding-row"
                  onClick={() => onOpenItemSearch(row.item?.name ?? `Item ${row.id}`)}
                >
                  <ItemIcon item={row.item ?? { name: "Item" }} />
                  <div>
                    <ItemGradeName name={row.item?.name ?? `Item ${row.id}`} rarity={row.item?.rarity} />
                    <span>{row.count.toLocaleString()} owned</span>
                  </div>
                  <strong>{row.value ? <Money value={row.value} /> : "-"}</strong>
                </button>
              ))}
            </div>
          ) : (
            <div className="general-card-list">
              {REPEATABLE_EARNING_OPTIONS.slice(0, 6).map((option) => (
                <button
                  key={option.title}
                  className="general-card"
                  onClick={() => onOpenActivity(option)}
                >
                  <strong>{option.title}</strong>
                  <span>{option.speed}</span>
                </button>
              ))}
            </div>
          )}
        </div>
      </section>
    </div>
  );
}

interface OwnedItemRow {
  id: number;
  count: number;
  item?: Gw2Item;
  value: number;
  materialCount: number;
  bankCount: number;
  sharedCount: number;
  characterCount: number;
  isCraftingItem: boolean;
}

function AccountItemsPage({
  accountSnapshot,
  accountItems,
  currencies,
  currencyCatalogState,
  analysisState,
  onAnalyze,
  onOpenItem,
  onOpenCurrency,
}: {
  accountSnapshot: AccountSnapshot | null;
  accountItems: Map<number, Gw2Item>;
  currencies: Gw2Currency[];
  currencyCatalogState: LoadState;
  analysisState: LoadState;
  onAnalyze: () => void;
  onOpenItem: (item: Gw2Item) => void;
  onOpenCurrency: (currency: GuideCurrencyDefinition) => void;
}) {
  const [search, setSearch] = useState("");
  const rows = useMemo(
    () => (accountSnapshot ? buildOwnedItemRows(accountSnapshot, accountItems) : []),
    [accountItems, accountSnapshot],
  );
  const walletAmounts = useMemo(
    () => new Map((accountSnapshot?.wallet ?? []).map((entry) => [entry.id, entry.value])),
    [accountSnapshot],
  );
  const currencyRows = useMemo(
    () => buildCurrencyRows(currencies, walletAmounts),
    [currencies, walletAmounts],
  );
  const normalizedSearch = search.trim().toLowerCase();
  const filteredRows = useMemo(() => {
    if (!normalizedSearch) {
      return rows;
    }

    return rows.filter((row) => {
      const item = row.item;
      return (
        String(row.id).includes(normalizedSearch) ||
        item?.name.toLowerCase().includes(normalizedSearch) ||
        item?.type.toLowerCase().includes(normalizedSearch) ||
        item?.rarity.toLowerCase().includes(normalizedSearch) ||
        describeOwnedItemSources(row).toLowerCase().includes(normalizedSearch)
      );
    });
  }, [normalizedSearch, rows]);
  const filteredCurrencyRows = useMemo(() => {
    if (!normalizedSearch) {
      return currencyRows;
    }

    return currencyRows.filter((row) => {
      const haystack = [
        row.currency.id,
        row.currency.name,
        row.description,
        row.definition.summary,
        row.amount,
        row.displayOrder,
      ]
        .join(" ")
        .toLowerCase();
      return haystack.includes(normalizedSearch);
    });
  }, [currencyRows, normalizedSearch]);
  const craftingRows = filteredRows.filter((row) => row.isCraftingItem);
  const normalRows = filteredRows.filter((row) => !row.isCraftingItem);
  const totalOwnedCount = rows.reduce((sum, row) => sum + row.count, 0);
  const totalKnownValue = rows.reduce((sum, row) => sum + row.value, 0);

  if (!accountSnapshot) {
    return (
      <div className="focused-page">
        <section className="page-header">
          <div>
            <span className="eyebrow">My GW2 Account</span>
            <h2>Account Items</h2>
            <p>Load a GW2 API key to list material storage, bank, shared inventory, and character inventory items.</p>
          </div>
          <button className="icon-button primary" onClick={onAnalyze}>
            {analysisState === "loading" ? <Loader2 className="spin" /> : <ShieldCheck />}
            <span>{analysisState === "loading" ? "Loading" : "Analyze API"}</span>
          </button>
        </section>
        <section className="surface account-required-panel">
          <Boxes />
          <h2>Account data required</h2>
          <p>This page needs the account API key so the app can read owned items locally.</p>
        </section>
      </div>
    );
  }

  return (
    <div className="focused-page account-items-page">
      <section className="page-header">
        <div>
          <span className="eyebrow">My GW2 Account</span>
          <h2>Account Items</h2>
          <p>
            Every loaded item stack for {accountSnapshot.tokenInfo.name}, with crafting materials shown before normal items.
          </p>
        </div>
        <button className="icon-button primary" onClick={onAnalyze}>
          {analysisState === "loading" ? <Loader2 className="spin" /> : <RefreshCcw />}
          <span>{analysisState === "loading" ? "Refreshing" : "Refresh Account"}</span>
        </button>
      </section>

      <section className="account-metrics">
        <Metric icon={<Boxes />} label="Unique Items" value={rows.length.toLocaleString()} />
        <Metric icon={<Coins />} label="Wallet Currencies" value={currencyRows.length.toLocaleString()} />
        <Metric icon={<Database />} label="Total Stack Count" value={totalOwnedCount.toLocaleString()} />
        <Metric icon={<Hammer />} label="Crafting Items" value={craftingRows.length.toLocaleString()} />
        <Metric
          icon={<Coins />}
          label="Known TP Value"
          value={totalKnownValue ? <Money value={totalKnownValue} /> : "Load market"}
          tone={totalKnownValue ? "positive" : "muted"}
        />
      </section>

      <section className="surface account-items-browser">
        <div className="section-title">
          <PackageSearch />
          <h3>Owned Items</h3>
        </div>
        <label className="search-box">
          <Search />
          <input
            value={search}
            onChange={(event) => setSearch(event.target.value)}
            placeholder="Search owned item, type, rarity"
          />
        </label>

        <OwnedItemTable
          title="Crafting Items"
          rows={craftingRows}
          emptyText="No owned crafting items match the current search."
          onOpenItem={onOpenItem}
        />
        <CurrencyMaterialTable
          rows={filteredCurrencyRows}
          loading={currencyCatalogState === "loading" && currencyRows.length === 0}
          emptyText={
            currencyCatalogState === "error"
              ? "Unable to load wallet currencies right now."
              : "No wallet currencies match the current search."
          }
          onOpenCurrency={onOpenCurrency}
        />
        <OwnedItemTable
          title="Normal Items"
          rows={normalRows}
          emptyText="No owned normal items match the current search."
          onOpenItem={onOpenItem}
        />
      </section>
    </div>
  );
}

interface CurrencyRow {
  currency: Gw2Currency;
  definition: GuideCurrencyDefinition;
  amount: number;
  description: string;
  displayOrder: number;
}

function buildCurrencyRows(
  currencies: Gw2Currency[],
  walletAmounts: Map<number, number>,
): CurrencyRow[] {
  const displayableCurrencies = currencies
    .filter((currency) => currency.id !== 1)
    .map((currency) => normalizeCurrencyForDisplay(currency))
    .filter((currency): currency is Gw2Currency => Boolean(currency));

  return displayableCurrencies
    .map((currency, index) => {
      const normalizedCurrency = normalizeCurrencyForDisplay(currency);
      if (!normalizedCurrency) {
        return null;
      }

      const amount = walletAmounts.get(currency.id) ?? 0;
      return {
        currency: normalizedCurrency,
        definition: buildCurrencyGuideDefinition(normalizedCurrency, amount),
        amount,
        description: formatCurrencyDescription(normalizedCurrency.description),
        displayOrder: index + 1,
      };
    })
    .filter((row): row is CurrencyRow => Boolean(row));
}

function CurrenciesPage({
  currencies,
  currencyCatalogState,
  accountSnapshot,
  catalog,
  analysisState,
  selectedCurrency,
  onRefreshAccount,
  onRefreshCurrencies,
  onOpenCurrency,
  onOpenDetail,
  onCloseCurrency,
  onOpenPage,
}: {
  currencies: Gw2Currency[];
  currencyCatalogState: LoadState;
  accountSnapshot: AccountSnapshot | null;
  catalog: MarketItem[];
  analysisState: LoadState;
  selectedCurrency: GuideCurrencyDefinition | null;
  onRefreshAccount: () => void;
  onRefreshCurrencies: () => void;
  onOpenCurrency: (currency: GuideCurrencyDefinition) => void;
  onOpenDetail: (item: Gw2Item) => void;
  onCloseCurrency: () => void;
  onOpenPage: (page: ActivePage) => void;
}) {
  const [search, setSearch] = useState("");
  const walletAmounts = useMemo(
    () => new Map((accountSnapshot?.wallet ?? []).map((entry) => [entry.id, entry.value])),
    [accountSnapshot],
  );
  const rows = useMemo(
    () => buildCurrencyRows(currencies, walletAmounts),
    [currencies, walletAmounts],
  );
  const normalizedSearch = search.trim().toLowerCase();
  const filteredRows = useMemo(() => {
    if (!normalizedSearch) {
      return rows;
    }

    return rows.filter((row) => {
      const haystack = [
        row.currency.id,
        row.currency.name,
        row.description,
        row.definition.summary,
        row.amount,
        row.displayOrder,
      ]
        .join(" ")
        .toLowerCase();
      return haystack.includes(normalizedSearch);
    });
  }, [normalizedSearch, rows]);
  const ownedRows = rows.filter((row) => row.amount > 0);
  const pageBody = (
    <div className="focused-page account-items-page currencies-page">
      <section className="page-header">
        <div>
          <span className="eyebrow">My GW2 Account</span>
          <h2>Currencies</h2>
          <p>
            {accountSnapshot
              ? `All wallet currencies for ${accountSnapshot.tokenInfo.name}, including currencies with a zero balance.`
              : "All official wallet currencies, with account amounts shown after loading a GW2 API key."}
          </p>
        </div>
        <div className="page-actions">
          <button className="icon-button" onClick={onRefreshCurrencies} disabled={currencyCatalogState === "loading"}>
            {currencyCatalogState === "loading" ? <Loader2 className="spin" /> : <RefreshCcw />}
            <span>{currencyCatalogState === "loading" ? "Loading" : "Refresh Catalog"}</span>
          </button>
          <button className="icon-button primary" onClick={onRefreshAccount} disabled={analysisState === "loading"}>
            {analysisState === "loading" ? <Loader2 className="spin" /> : <ShieldCheck />}
            <span>{analysisState === "loading" ? "Refreshing" : accountSnapshot ? "Refresh Account" : "Analyze API"}</span>
          </button>
        </div>
      </section>

      <section className="account-metrics">
        <Metric icon={<Coins />} label="Tracked Currencies" value={rows.length.toLocaleString()} />
        <Metric icon={<Database />} label="Owned Balances" value={ownedRows.length.toLocaleString()} tone={ownedRows.length ? "positive" : "muted"} />
        <Metric icon={<WalletIcon />} label="Wallet Entries" value={accountSnapshot ? Math.max(0, accountSnapshot.wallet.length - 1).toLocaleString() : "No API"} />
        <Metric icon={<Coins />} label="Coin Balance" value={accountSnapshot ? <Money value={accountSnapshot.coins} /> : "No API"} tone={accountSnapshot ? "positive" : "muted"} />
      </section>

      <section className="surface account-items-browser currencies-browser">
        <div className="section-title">
          <Coins />
          <h3>Currency Wallet</h3>
        </div>
        <label className="search-box">
          <Search />
          <input
            value={search}
            onChange={(event) => setSearch(event.target.value)}
            placeholder="Search currency, description, amount"
          />
        </label>

        <CurrencyTable
          rows={filteredRows}
          loading={currencyCatalogState === "loading" && rows.length === 0}
          emptyText={
            currencyCatalogState === "error"
              ? "Unable to load the currency catalog. Try refreshing the catalog."
              : "No currencies match the current search."
          }
          selectedCurrencyName={selectedCurrency?.name ?? null}
          onOpenCurrency={onOpenCurrency}
        />
      </section>
    </div>
  );

  if (!selectedCurrency) {
    return pageBody;
  }

  return (
    <div className="market-workspace account-currency-workspace">
      <aside className="market-panel account-currency-list-panel">
        {pageBody}
      </aside>
      <MarketSplitHandle />
      <GuideCurrencyDetailPane
        currency={selectedCurrency}
        accountSnapshot={accountSnapshot}
        catalog={catalog}
        onClose={onCloseCurrency}
        onOpenDetail={onOpenDetail}
        onOpenPage={onOpenPage}
      />
    </div>
  );
}

function CurrencyTable({
  rows,
  loading,
  emptyText,
  selectedCurrencyName,
  onOpenCurrency,
}: {
  rows: CurrencyRow[];
  loading: boolean;
  emptyText: string;
  selectedCurrencyName: string | null;
  onOpenCurrency: (currency: GuideCurrencyDefinition) => void;
}) {
  const { sortedRows, renderHeader } = useSortableRows<
    CurrencyRow,
    "currency" | "amount" | "description" | "order"
  >(
    rows,
    { key: "order", direction: "asc" },
    {
      currency: (left, right) => compareStringValue(left.currency.name, right.currency.name),
      amount: (left, right) => compareNumberValue(left.amount, right.amount),
      description: (left, right) => compareStringValue(left.description, right.description),
      order: (left, right) => compareNumberValue(left.displayOrder, right.displayOrder),
    },
  );

  return (
    <div className="owned-item-section">
      <div className="owned-item-section-head">
        <h4>All Currencies</h4>
        <span>{rows.length.toLocaleString()}</span>
      </div>
      {loading ? (
        <SkeletonRows />
      ) : rows.length > 0 ? (
        <div className="craft-table-wrap">
          <table className="craft-profit-table account-item-table currency-table">
            <thead>
              <tr>
                {renderHeader("currency", "Currency")}
                {renderHeader("amount", "Account Amount")}
                {renderHeader("description", "Description")}
                {renderHeader("order", "Order")}
              </tr>
            </thead>
            <tbody>
              {sortedRows.map((row) => (
                <tr
                  key={row.currency.id}
                  className={`clickable-row ${selectedCurrencyName === row.currency.name ? "selected" : ""}`}
                  onClick={() => onOpenCurrency(row.definition)}
                >
                  <td>
                    <button
                      type="button"
                      className="table-item-button"
                      onClick={(event) => {
                        event.stopPropagation();
                        onOpenCurrency(row.definition);
                      }}
                    >
                      <span className="table-item-cell">
                        <ItemIcon
                          item={{ id: row.currency.id, name: row.currency.name, icon: row.definition.icon }}
                          showFavoriteBadge={false}
                        />
                        <span className="item-copy">
                          <strong>{row.currency.name}</strong>
                        </span>
                      </span>
                    </button>
                  </td>
                  <td>{row.amount > 0 ? row.amount.toLocaleString() : "0"}</td>
                  <td>{row.description || row.definition.summary}</td>
                  <td>{row.displayOrder.toLocaleString()}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      ) : (
        <p className="muted-copy">{emptyText}</p>
      )}
    </div>
  );
}

