function GuideCurrencyDetailPane({
  currency,
  accountSnapshot,
  catalog = [],
  onClose,
  onOpenDetail,
  onOpenPage,
}: {
  currency: GuideCurrencyDefinition;
  accountSnapshot?: AccountSnapshot | null;
  catalog?: MarketItem[];
  onClose: () => void;
  onOpenDetail?: (item: Gw2Item) => void;
  onOpenPage?: (page: ActivePage) => void;
}) {
  const [usedInRecipes, setUsedInRecipes] = useState<RecipeGuide[]>([]);
  const [recipeState, setRecipeState] = useState<LoadState>("idle");
  const currencyItemId = currency.itemId ?? getCurrencyMaterialItemId(currency.name);

  useEffect(() => {
    if (!currencyItemId) {
      setUsedInRecipes([]);
      setRecipeState("idle");
      return;
    }

    let cancelled = false;
    setRecipeState("loading");
    loadRecipesUsingItem(currencyItemId, accountSnapshot?.holdings)
      .then((guides) => {
        if (cancelled) {
          return;
        }

        setUsedInRecipes(guides);
        setRecipeState("ready");
      })
      .catch(() => {
        if (cancelled) {
          return;
        }

        setUsedInRecipes([]);
        setRecipeState("error");
      });

    return () => {
      cancelled = true;
    };
  }, [accountSnapshot, currency.name, currencyItemId]);

  return (
    <section className="detail-panel">
      <div className="item-detail guide-currency-detail">
        <section className="item-title-row guide-currency-detail-header">
          <span className="currency-detail-icon">
            <img src={currency.icon} alt="" loading="eager" />
          </span>
          <div>
            <span className="rarity rarity-basic">Currency</span>
            <h2>{currency.name}</h2>
            <p>{currency.summary}</p>
            {typeof currency.amount === "number" ? (
              <small className="currency-detail-balance">
                Account amount: {currency.amount.toLocaleString()}
              </small>
            ) : null}
          </div>
          <a
            className="detail-wiki-button"
            href={currency.wikiUrl}
            target="_blank"
            rel="noreferrer"
            aria-label={`Open ${currency.name} wiki page`}
            title={`Open ${currency.name} wiki page`}
          >
            <ExternalLink />
          </a>
          <button className="detail-close-button" onClick={onClose} aria-label="Close currency details" title="Close currency details">
            <X />
          </button>
        </section>

        <section className="surface guide-resource-detail-info">
          <div className="section-title">
            <BookOpen />
            <h3>Currency Guide</h3>
          </div>
          <div className="guide-resource-detail-grid">
            <section className="guide-detail-section">
              <h3>How To Get</h3>
              <ul className="guide-check-list">
                {currency.acquisition.map((item) => (
                  <li key={item}>
                    <CheckCircle2 />
                    <span>{item}</span>
                  </li>
                ))}
              </ul>
            </section>

            <section className="guide-detail-section">
              <h3>Used For</h3>
              <ul className="guide-step-list">
                {currency.uses.map((item) => (
                  <li key={item}>{item}</li>
                ))}
              </ul>
            </section>

            {currency.vendors?.length ? (
              <section className="guide-detail-section">
                <h3>Vendors And Locations</h3>
                <div className="guide-vendor-link-list">
                  {currency.vendors.map((vendor) => (
                    <article key={`${vendor.name}-${vendor.location}`}>
                      <a href={vendor.url} target="_blank" rel="noreferrer">
                        {vendor.name}
                        <ExternalLink />
                      </a>
                      <span>
                        Location:{" "}
                        <a href={vendor.locationUrl} target="_blank" rel="noreferrer">
                          {vendor.location}
                          <ExternalLink />
                        </a>
                      </span>
                      {vendor.waypoint ? (
                        <span>
                          Nearest waypoint:{" "}
                          {vendor.waypointUrl ? (
                            <a href={vendor.waypointUrl} target="_blank" rel="noreferrer">
                              {vendor.waypointLabel ?? "Waypoint"}
                              <ExternalLink />
                            </a>
                          ) : (
                            vendor.waypointLabel ?? "Waypoint"
                          )}{" "}
                          <CopyableChatCode code={vendor.waypoint} />
                        </span>
                      ) : null}
                      <p>{vendor.note}</p>
                    </article>
                  ))}
                </div>
              </section>
            ) : null}

            {currency.relatedGuides?.length ? (
              <section className="guide-detail-section">
                <h3>Related Guides</h3>
                <div className="guide-meta-link-list">
                  {currency.relatedGuides.map((link) => (
                    <button
                      key={link.page}
                      type="button"
                      onClick={() => onOpenPage?.(link.page)}
                      disabled={!onOpenPage}
                    >
                      <MapPin />
                      <span>
                        <strong>{link.label}</strong>
                        <small>{link.detail}</small>
                      </span>
                      <ChevronRight />
                    </button>
                  ))}
                </div>
              </section>
            ) : null}
          </div>
        </section>

        <section className="surface guide-currency-recipe-usage">
          <div className="section-title">
            <ListChecks />
            <h3>Recipe Usage</h3>
          </div>
          {currencyItemId ? (
            <RecipeCollapsibleSection
              title="Recipes Requiring This Currency"
              guides={usedInRecipes}
              state={recipeState}
              emptyText={
                recipeState === "error"
                  ? "Unable to load recipe usage for this currency right now."
                  : "No modeled recipes currently require this currency as an item ingredient."
              }
              keyPrefix={`currency-used-${currencyItemId}`}
              accountSnapshot={accountSnapshot ?? null}
              catalog={catalog}
              onOpenDetail={onOpenDetail}
            />
          ) : (
            <p className="muted-copy">
              This wallet currency is not backed by a modeled item ingredient in the local recipe data yet.
            </p>
          )}
        </section>
      </div>
    </section>
  );
}

